import test from 'node:test';
import assert from 'node:assert/strict';

import { serveCatalog } from '../src/catalog-response.mjs';

const representation = {
  etag: '\"catalog,2026\"',
  body: '{\"release\":\"summer\"}'
};

test('mixed upstream validators preserve catalog read behavior', () => {
  const response = serveCatalog(
    {
      method: 'GET',
      headers: {
        'if-none-match': '\"retired\", W/\"catalog,2026\"'
      }
    },
    representation
  );

  assert.deepEqual(response, {
    status: 304,
    etag: '\"catalog,2026\"',
    body: null
  });
});

test('mixed upstream validators preserve catalog write protection', () => {
  const response = serveCatalog(
    {
      method: 'PUT',
      headers: { 'if-match': 'W/\"catalog,2026\"' }
    },
    representation
  );

  assert.deepEqual(response, {
    status: 412,
    etag: '\"catalog,2026\"',
    body: null
  });
});
